SELECT etl_process_name
FROM etl_logs
WHERE status = 'Success';

SELECT study_id, COUNT(specimen_id) AS total_specimens
FROM specimens
GROUP BY study_id;

SELECT person_name
FROM persons
WHERE person_id IN (SELECT DISTINCT person_id FROM specimens);

SELECT SUM(quantity) AS total_specimens_used
FROM study_specimens
WHERE study_id = 0;
